+/** Keep only the final operation for each ordinary trait or relation pair.
+ * This is what makes a buffered add/remove invisible to subscriptions when the
+ * pair ends in its original state, and makes repeated values last-write-wins. */
+function compact(commands: Command[]) {
+    const keep = new Array<boolean>(commands.length).fill(true);
+    const seen = new Set<string>();
+    const wildcardBefore = new Set<string>();
+    for (let i = commands.length - 1; i >= 0; i--) {
+        const command = commands[i];
+        if (command.type !== 'add' && command.type !== 'remove' && command.type !== 'exclusive') continue;
+        if (command.type === 'exclusive') {
